using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class NavigationTraining : TrainingContentBase
{
    public NavigationTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigating the App",
            Slug = "navigating-the-app-overview",
            Summary = "A comprehensive overview of the sidebar, header, notifications, search, theme switching, and navigation structure.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["onboarding","navigation"]""",
            ContentJson = """{"body":"## Navigating the App\n\nForge has a consistent layout across every page: a collapsible sidebar on the left, a fixed header bar at the top, and a scrollable content area in the center.\n\n### Sidebar Navigation\n\nThe sidebar is your primary navigation tool. In its collapsed state, it shows only icons (52px wide). Click the chevron toggle at the top to see full labels (200px wide). Your sidebar state is saved to localStorage, so it persists across sessions on the same browser.\n\n**Sidebar sections:**\n- **Dashboard** — your daily home page with widgets\n- **Board** — the kanban board for active jobs\n- **Backlog** — all jobs not on the board\n- **Planning** — planning cycle management\n- **Parts** — parts catalog with BOMs and process steps\n- **Inventory** — stock levels, bins, movements\n- **Customers** — CRM with contacts and addresses\n- **Vendors** — vendor management and PO history\n- **Purchase Orders** — PO creation and receiving\n- **Sales Orders** — order management\n- **Quotes** — price quoting\n- **Shipments** — shipping and tracking\n- **Invoices** — billing (standalone mode)\n- **Payments** — payment recording (standalone mode)\n- **Leads** — sales pipeline\n- **Expenses** — expense submission and approval\n- **Assets** — equipment and tooling register\n- **Time Tracking** — timers and manual entries\n- **Quality** — QC templates and inspections\n- **Reports** — report builder and saved reports\n- **Calendar** — job due dates and PO deliveries\n- **Chat** — internal messaging\n- **AI** — AI assistant\n- **Training** — learning modules and paths\n- **Admin** — system configuration (admin only)\n- **Account** — your profile, compliance, security\n\n### Header Bar\n\nThe 44px header bar stays fixed at the top of every page. It contains:\n- **Search icon** — opens global search (searches jobs, parts, customers, vendors, and more)\n- **Notification bell** — shows unread count badge; click to open the notification panel\n- **Chat icon** — opens the chat panel; shows unread message count\n- **Theme toggle** — a sun/moon icon that switches between Light and Dark themes\n- **User avatar** — opens the user menu with account settings, language, and logout\n\n### Theme Switching\n\nClick the theme toggle icon (sun/moon) in the header to switch between Light and Dark themes. Your choice is saved to localStorage and syncs across your browser tabs immediately. Dark theme swaps all CSS custom properties (--bg, --surface, --text, etc.).\n\n### Keyboard Shortcuts\n\nPress **/** (forward slash) anywhere to see available keyboard shortcuts. Common shortcuts include:\n- **Ctrl+K** — focus global search\n- **/** — open the keyboard shortcuts help\n- **Escape** — close current dialog or panel\n\n### URL-Based Navigation\n\nEvery significant view state is reflected in the URL. This means:\n- You can bookmark any page, tab, or filtered view\n- Browser back/forward buttons work naturally\n- Sharing a URL puts the recipient on the exact same view\n- Refreshing the page preserves your state","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigating the App — Guided Tour",
            Slug = "navigating-the-app",
            Summary = "A guided tour of the sidebar, header, notifications, and main navigation areas.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["onboarding","navigation","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Take the Tour","steps":[{"element":".sidebar","popover":{"title":"Sidebar Navigation","description":"The sidebar holds all your navigation links, organized into groups (Operations, Sales, Production, and more). Click a group to drill into its items; click the chevron toggle at the top to show or hide the full labels.","side":"right"}},{"element":".app-header","popover":{"title":"App Header","description":"The header stays visible on every page. Use the search icon to do a global search across jobs, parts, customers, and more.","side":"bottom"}},{"element":".app-header__actions","popover":{"title":"Notifications","description":"The bell icon shows your unread notification count. Click it to open the notification panel — you'll see job updates, assignments, and system alerts here.","side":"bottom"}},{"element":".user-trigger","popover":{"title":"User Menu","description":"Your avatar in the top-right opens the user menu. From here you can access your account settings, change your language, or log out. (The theme toggle is a separate sun/moon icon in the header.)","side":"bottom"}},{"element":".dashboard-content","popover":{"title":"Dashboard Widgets","description":"Your dashboard shows open jobs, today's tasks, active timers, and cycle progress. It updates in real time as work moves through the board.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigation Field Reference",
            Slug = "navigation-field-reference",
            Summary = "Complete reference for every navigation element, header control, sidebar section, and keyboard shortcut.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["navigation","reference"]""",
            ContentJson = """{"title":"Navigation Field Reference","groups":[{"heading":"Header Bar Controls","items":[{"label":"Search icon (magnifying glass)","value":"Opens global search overlay. Type to search across jobs, parts, customers, vendors, POs, and more. Results grouped by entity type. Press Ctrl+K to focus."},{"label":"Notification bell","value":"Shows unread notification count as a red badge. Click to open notification panel. Panel has tabs: All, Messages, Alerts. Supports mark-read, pin, dismiss, and dismiss-all."},{"label":"Chat icon","value":"Opens the chat slide-out panel. Shows unread message count badge. Panel lists conversations with last message preview and timestamp."},{"label":"User avatar","value":"Opens user menu dropdown. Contains: Account Settings, About, language switcher, Logout. The light/dark theme toggle is a separate sun/moon icon in the header, not in this menu. Avatar shows your initials on your chosen background color."}]},{"heading":"Sidebar Sections","items":[{"label":"Sidebar width","value":"Collapsed: 52px (icons only). Expanded: 200px (icons + labels). State saved to user preferences."},{"label":"Collapse/expand","value":"Click the chevron toggle at the top of the sidebar to expand or collapse it."},{"label":"Active indicator","value":"Current page is highlighted with a left border accent and background tint on the sidebar icon."},{"label":"Section grouping","value":"Related items grouped into expandable groups (Operations, Sales, Production, Inventory, Purchasing, People, Insights). Dividers separate Dashboard, the main groups, and the pinned Shop Floor + Admin."}]},{"heading":"Keyboard Shortcuts","items":[{"label":"/ (forward slash)","value":"Open the keyboard shortcuts help dialog"},{"label":"Ctrl+K","value":"Focus the global search input"},{"label":"Escape","value":"Close current dialog, panel, or overlay"},{"label":"Q then a letter","value":"Navigation chords: Q then D (Dashboard), K (Board), B (Backlog), P (Parts), I (Inventory), R (Reports), T (Time)"}]},{"heading":"URL State Patterns","items":[{"label":"Tabs","value":"Reflected as route segments: /admin/integrations, /inventory/receiving"},{"label":"Selected entity","value":"Query param: ?detail=job:1055, ?detail=part:42"},{"label":"Filters","value":"Query params: ?status=open&priority=high"},{"label":"Pagination","value":"Query params: ?page=2&pageSize=50"},{"label":"Wizard steps","value":"Query param: ?step=2"}]},{"heading":"Theme System","items":[{"label":"Light theme","value":"White backgrounds, dark text. CSS custom properties: --bg: #ffffff, --surface: #f8f8f8"},{"label":"Dark theme","value":"Default. Dark backgrounds, light text. Toggled via data-theme='dark' on <html>. CSS custom properties auto-swap."},{"label":"Persistence","value":"Saved to localStorage key 'forge-theme'. Syncs across tabs."},{"label":"Reduced motion","value":"Animations disabled when prefers-reduced-motion is set in OS settings."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigation Knowledge Check",
            Slug = "navigation-quiz",
            Summary = "Test your knowledge of app navigation, header controls, sidebar, keyboard shortcuts, and URL state.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/training"]""",
            Tags = """["navigation","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"nav1","text":"You want to search for a specific job number across the entire app. What is the fastest way?","options":[{"id":"a","text":"Navigate to Backlog and use the search filter"},{"id":"b","text":"Use the global search field in the header or press Ctrl+K to focus it","isCorrect":true},{"id":"c","text":"Go to Reports and run a Job Summary report"},{"id":"d","text":"Open the Kanban Board and scroll through columns"}],"explanation":"Global search in the header searches across all entity types (jobs, parts, customers, etc.) simultaneously. Press Ctrl+K to focus it instantly from any page."},{"id":"nav2","text":"You want to share the exact filtered view of the Backlog with a teammate. What do you do?","options":[{"id":"a","text":"Take a screenshot and send it via chat"},{"id":"b","text":"Copy the URL from your browser's address bar — filters are encoded in query params","isCorrect":true},{"id":"c","text":"Export the backlog to CSV and email it"},{"id":"d","text":"Save a report with the same filters"}],"explanation":"All filter state is reflected in the URL as query parameters. Copying the URL gives your teammate the exact same view, including filters, sorting, and pagination."},{"id":"nav3","text":"The notification bell shows a red badge with '5'. What does this mean?","options":[{"id":"a","text":"5 system errors occurred in the last hour"},{"id":"b","text":"You have 5 unread notifications","isCorrect":true},{"id":"c","text":"5 jobs are overdue"},{"id":"d","text":"5 compliance forms need attention"}],"explanation":"The badge count on the notification bell shows unread notifications. These can be job updates, assignment changes, mentions, or system alerts."},{"id":"nav4","text":"How do you switch between Light and Dark theme?","options":[{"id":"a","text":"Admin → Settings → Theme"},{"id":"b","text":"Click the sun/moon theme toggle icon in the header","isCorrect":true},{"id":"c","text":"Account → Profile → Appearance"},{"id":"d","text":"Press Ctrl+D to toggle"}],"explanation":"The theme toggle is a dedicated sun/moon icon button in the header (not in the avatar menu). Your choice is saved and syncs across browser tabs."},{"id":"nav5","text":"You're on the Expenses page and want to quickly navigate to Parts. Where do you click?","options":[{"id":"a","text":"Browser back button until you reach Parts"},{"id":"b","text":"Click the Parts icon in the left sidebar","isCorrect":true},{"id":"c","text":"Use the header breadcrumbs to navigate up"},{"id":"d","text":"Open global search and type 'Parts'"}],"explanation":"The sidebar is your primary navigation tool. Click the Parts icon (or its label if the sidebar is expanded) to navigate directly."},{"id":"nav6","text":"What keyboard shortcut opens the keyboard shortcuts help dialog?","options":[{"id":"a","text":"Ctrl+H"},{"id":"b","text":"F1"},{"id":"c","text":"/ (forward slash)","isCorrect":true},{"id":"d","text":"Ctrl+/"}],"explanation":"Press / (forward slash) from any page to see all available keyboard shortcuts. This works regardless of which page you're on."},{"id":"nav7","text":"The sidebar is collapsed and only showing icons. How do you see the full labels?","options":[{"id":"a","text":"Click the chevron toggle at the top of the sidebar","isCorrect":true},{"id":"b","text":"Press Ctrl+B to toggle the sidebar"},{"id":"c","text":"Go to Account → Preferences → Sidebar"},{"id":"d","text":"You cannot expand it — the icons are the only navigation"}],"explanation":"Click the chevron toggle at the top of the sidebar to expand it with full labels. Your preference is saved to localStorage."},{"id":"nav8","text":"You bookmarked a URL that ends with ?detail=job:1055. What happens when you open it?","options":[{"id":"a","text":"It shows an error because job detail URLs are temporary"},{"id":"b","text":"It opens the page and automatically opens the detail dialog for job 1055","isCorrect":true},{"id":"c","text":"It redirects to the Kanban Board filtered to job 1055"},{"id":"d","text":"It opens the job's PDF work order"}],"explanation":"The ?detail=type:id query parameter triggers the detail dialog to open automatically when the page loads. This makes bookmarks and shared links land on the exact view."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigation & Onboarding — Advanced Reference",
            Slug = "navigation-reference",
            Summary = "Edge-case and power-user reference for the onboarding wizard, securely-stored fields, help surfaces, and dashboard install variants.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/dashboard"]""",
            Tags = """["navigation","reference","advanced"]""",
            ContentJson = """{"body":"## W-4 Withholding — Dependents & Exempt\n\nStep 2 of the onboarding wizard (`?step=2`) collects federal W-4 data. The credit fields `w4QualifyingChildren` (Step 3a, $2,000 each) and `w4OtherDependents` ($500 each) feed the standard W-4 dependents calculation; their dollar total is summed automatically — workers enter counts, not dollars. `w4MultipleJobs`, `w4OtherIncome`, `w4Deductions`, and `w4ExtraWithholding` map directly to the 2020+ W-4 lines. Checking `w4ExemptFromWithholding` declares exemption: it suppresses/zeroes the credit and extra-withholding fields, since an exempt filer has no federal income tax withheld.\n\n## I-9 — List A vs List B + C Documents\n\nStep 4 (`?step=4`, `i9DocumentChoice`) follows USCIS Form I-9 Section 1. The employee provides EITHER one List A document (establishes both identity and work authorization — e.g. U.S. Passport, Permanent Resident Card, Employment Authorization Document) OR one List B document (identity — Driver's License, State ID Card) PLUS one List C document (work authorization). Selecting List A exposes `i9ListAType/Authority/Expiry` plus a file upload (`i9ListAFileAttachmentId`); selecting B+C exposes the paired `i9ListB*` and `i9ListC*` fieldsets, each with its own upload. Citizenship status (`i9CitizenshipStatus`) gates conditional rows: alien-registration number, I-94 number, foreign-passport number/country, and `i9WorkAuthExpiry`.\n\n## No-Income-Tax States\n\nStep 5 (`?step=5`) is state withholding. The wizard recognizes the no-income-tax states — `AK, FL, NV, SD, TN, TX, WA, WY` — via the `NO_INCOME_TAX_STATES` set. When the employee's work-location state is in this set, the state-withholding fields (`stateFilingStatus`, `stateAllowances`, `stateAdditionalWithholding`, `stateExempt`) are not required, because there is no state income tax to withhold. The applicable state derives from the employee's `WorkLocationId` (CompanyLocation), not a free-text entry.\n\n## Direct Deposit — Routing & Account\n\nStep 6 collects banking details for ACH payroll deposit: bank routing number (9-digit ABA), account number, and account type (checking/savings). These are entered once during onboarding and stored as securely-handled fields (see below). A worker who is paid by paper check can skip this step where the install permits.\n\n## Securely-Stored Fields & Draft Resume\n\nSensitive identifiers (SSN, bank routing/account, foreign-document numbers) are flagged as secure: the wizard tracks only a boolean presence indicator (e.g. `hasAlienRegNumber`, `hasI94Number`, `hasForeignPassportNumber`, `hasListADocNumber`) in client state rather than echoing the raw value back. Progress is draft-resumable — the wizard persists review state under the `forge-onboarding-review-state` key and the URL `?step=N` is the source of truth, so closing and reopening `/onboarding` returns the worker to the same step with prior entries intact.\n\n## Acknowledgments — Workers' Comp vs Handbook\n\nThe Acknowledgments step presents one checkbox per required policy. These are distinct documents: the workers' compensation acknowledgment (state-mandated notice of comp coverage and injury-reporting procedure) is separate from the employee handbook acknowledgment (receipt and agreement to company policy). Each must be individually acknowledged; the set of required acknowledgments is install-configurable.\n\n## Per-Page Help Tours vs the Training Panel\n\nTwo distinct help surfaces share the header. The **Training context panel** (book/training icon, `TrainingContextPanelComponent`, toggled via `showTrainingPanel`) lists the published training modules whose `AppRoutes` match the current page — this Reference module appears there on `/dashboard`. Separately, **per-page guided tours** are driver.js Walkthrough modules launched on demand (the \"Take the Tour\" button) that highlight live DOM elements step-by-step. The panel is a reading list scoped to the route; a tour is an interactive overlay. The header also exposes the AI Help panel and a global AI search column (entity results + RAG answer) that are help-adjacent but not training content.\n\n## Dashboard Install Variants\n\nThe dashboard landing (`/dashboard`, the default `AppRoute` for navigation modules) renders different widget sets per install because capability gating hides widgets tied to disabled features (e.g. accounting, payroll, or chat widgets disappear when their `CAP-*` is off). Layout and the customize/Focus/Ambient/export controls persist per user via `user_preferences` (`dashboard:layout`). Because the visible surface depends on both the install's capability set and the user's saved layout, two users on different installs can see materially different dashboards from the same route.","sections":[]}"""
        });

        Log.Information("Seeded Navigation training modules");
    }
}
